mapper.select:
SELECT o.outbound_id AS outboundId, o.work_order_id AS workOrderId, o.outbound_date AS outboundDate, o.due_date AS dueDate, o.status AS statusCode, CASE WHEN o.status = 'ISSUED' THEN '출고완료' ELSE '미출고' END AS statusDisplay, o.handled_by AS handledBy FROM material_outbound o
AND o.status = #{status}
AND (o.outbound_id LIKE CONCAT('%', #{keyword}, '%') OR o.work_order_id LIKE CONCAT('%', #{keyword}, '%'))
AND DATE(o.outbound_date) >= #{startDate}
AND DATE(o.outbound_date) <= #{endDate}
ORDER BY
o.outbound_id o.work_order_id o.outbound_date o.due_date o.status o.outbound_date
ASC DESC
ORDER BY o.outbound_date DESC
LIMIT #{perPageNum} OFFSET #{pageStart}

SELECT COUNT(*) 
FROM material_outbound o


    AND o.status = #{status}


